'use client';

import * as React from 'react';
import {
  motion,
  type HTMLMotionProps,
  type TargetAndTransition,
  type Transition,
  useReducedMotion,
} from 'motion/react';

import { useAutoHeight } from './use-auto-height';

type AutoHeightProps = {
  children: React.ReactNode;
  deps?: React.DependencyList;
  animate?: TargetAndTransition;
  transition?: Transition;
} & Omit<HTMLMotionProps<'div'>, 'animate'>;

function AutoHeight({
  children,
  deps = [],
  transition = {
    type: 'spring',
    stiffness: 300,
    damping: 30,
    bounce: 0,
    restDelta: 0.01,
  },
  style,
  animate,
  ...props
}: AutoHeightProps) {
  const { ref, height } = useAutoHeight<HTMLDivElement>(deps);
  const shouldReduceMotion = useReducedMotion();

  return (
    <motion.div
      style={{
        ...(height === undefined ? {} : { overflow: 'hidden' }),
        ...style,
      }}
      animate={height === undefined ? undefined : { ...animate, height }}
      transition={shouldReduceMotion ? { duration: 0 } : transition}
      {...props}
    >
      <div ref={ref}>{children}</div>
    </motion.div>
  );
}

export { AutoHeight, type AutoHeightProps };

'use client';

import * as React from 'react';

type AutoHeightOptions = {
  includeParentBox?: boolean;
  includeSelfBox?: boolean;
};

export function useAutoHeight<T extends HTMLElement = HTMLDivElement>(
  deps: React.DependencyList = [],
  options: AutoHeightOptions = {
    includeParentBox: true,
    includeSelfBox: false,
  },
) {
  const ref = React.useRef<T | null>(null);
  const roRef = React.useRef<ResizeObserver | null>(null);
  const [height, setHeight] = React.useState<number>();

  const measure = React.useCallback(() => {
    const el = ref.current;
    if (!el) return 0;

    const base = el.getBoundingClientRect().height || 0;

    let extra = 0;

    if (options.includeParentBox && el.parentElement) {
      const cs = getComputedStyle(el.parentElement);
      const paddingY =
        (parseFloat(cs.paddingTop || '0') || 0) +
        (parseFloat(cs.paddingBottom || '0') || 0);
      const borderY =
        (parseFloat(cs.borderTopWidth || '0') || 0) +
        (parseFloat(cs.borderBottomWidth || '0') || 0);
      const isBorderBox = cs.boxSizing === 'border-box';
      if (isBorderBox) {
        extra += paddingY + borderY;
      }
    }

    if (options.includeSelfBox) {
      const cs = getComputedStyle(el);
      const paddingY =
        (parseFloat(cs.paddingTop || '0') || 0) +
        (parseFloat(cs.paddingBottom || '0') || 0);
      const borderY =
        (parseFloat(cs.borderTopWidth || '0') || 0) +
        (parseFloat(cs.borderBottomWidth || '0') || 0);
      const isBorderBox = cs.boxSizing === 'border-box';
      if (isBorderBox) {
        extra += paddingY + borderY;
      }
    }

    const dpr =
      typeof window !== 'undefined' ? window.devicePixelRatio || 1 : 1;
    const total = Math.ceil((base + extra) * dpr) / dpr;

    return total;
  }, [options.includeParentBox, options.includeSelfBox]);

  React.useLayoutEffect(() => {
    const el = ref.current;
    if (!el) return;
    let frame = 0;

    setHeight(measure());

    if (roRef.current) {
      roRef.current.disconnect();
      roRef.current = null;
    }

    if (typeof ResizeObserver === 'undefined') return;

    const ro = new ResizeObserver(() => {
      const next = measure();
      cancelAnimationFrame(frame);
      frame = requestAnimationFrame(() => setHeight(next));
    });

    ro.observe(el);

    roRef.current = ro;

    return () => {
      cancelAnimationFrame(frame);
      ro.disconnect();
      roRef.current = null;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [...deps, measure]);

  React.useLayoutEffect(() => {
    if (height === undefined) {
      const next = measure();
      setHeight(next);
    }
  }, [height, measure]);

  return { ref, height } as const;
}
